class ExamRoom:
    def __init__(self, n):
        self.n = n
        self.occupied = set()

    def seat(self):
        if not self.occupied:
            self.occupied.add(0)
            return 0
        best_seat, best_dist = 0, -1
        for seat in range(self.n):
            if seat in self.occupied:
                continue
            dist = min(abs(seat - o) for o in self.occupied)
            if dist > best_dist:
                best_dist = dist
                best_seat = seat
        self.occupied.add(best_seat)
        return best_seat

    def leave(self, p):
        self.occupied.discard(p)

