import bisect

class ExamRoom:
    def __init__(self, n):
        self.n = n
        self.students = []

    def seat(self):
        if not self.students:
            self.students.append(0)
            return 0
        best_seat = 0
        best_dist = self.students[0]
        for i in range(len(self.students) - 1):
            l, r = self.students[i], self.students[i + 1]
            d = (r - l) // 2
            if d > best_dist:
                best_dist = d
                best_seat = l + d
        end_dist = self.n - 1 - self.students[-1]
        if end_dist > best_dist:
            best_dist = end_dist
            best_seat = self.n - 1
        bisect.insort(self.students, best_seat)
        return best_seat

    def leave(self, p):
        idx = bisect.bisect_left(self.students, p)
        if idx < len(self.students) and self.students[idx] == p:
            self.students.pop(idx)

