class ExamRoom {
    constructor(n) {
        this.n = n;
        this.students = [];
    }
    seat() {
        if (this.students.length === 0) {
            this.students.push(0);
            return 0;
        }
        let bestSeat = 0;
        let bestDist = this.students[0];
        for (let i = 0; i < this.students.length - 1; i++) {
            const l = this.students[i], r = this.students[i + 1];
            const d = Math.floor((r - l) / 2);
            if (d > bestDist) {
                bestDist = d;
                bestSeat = l + d;
            }
        }
        const endDist = this.n - 1 - this.students[this.students.length - 1];
        if (endDist > bestDist) {
            bestDist = endDist;
            bestSeat = this.n - 1;
        }
        let lo = 0, hi = this.students.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (this.students[mid] < bestSeat) lo = mid + 1; else hi = mid;
        }
        this.students.splice(lo, 0, bestSeat);
        return bestSeat;
    }
    leave(p) {
        let lo = 0, hi = this.students.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (this.students[mid] < p) lo = mid + 1; else hi = mid;
        }
        if (lo < this.students.length && this.students[lo] === p) {
            this.students.splice(lo, 1);
        }
    }
}
